#!/bin/bash set -euo pipefail EMAIL="csc@computersystemconsulting.ca" COMPOSE_FILE="/opt/comserv/Comserv/docker-compose.server.yml" DEPLOY_LOG="/var/log/comserv-deploy.log" HOSTNAME_VAL=$(hostname) MAX_HEALTH_WAIT=120 IMAGES=("shantamcsbain/comserv-web-prod:latest" "shantamcsbain/comserv-api-prod:latest") CONTAINERS=("comserv2-web-prod" "comserv2-api-prod") exec > >(tee -a "$DEPLOY_LOG") 2>&1 send_notification() { local subject="$1" local body="$2" echo -e "Subject: $subject\n\n$body" | mail -s "$subject" "$EMAIL" || true } trap 'send_notification "Comserv Deploy FAILED on $HOSTNAME_VAL" "Deployment failed at $(date). Check $DEPLOY_LOG"; exit 1' ERR for i in "${!IMAGES[@]}"; do docker pull "${IMAGES[$i]}" done docker-compose -f "$COMPOSE_FILE" down docker-compose -f "$COMPOSE_FILE" up -d for c in "${CONTAINERS[@]}"; do for ((i=0; i<MAX_HEALTH_WAIT; i+=5)); do if docker inspect --format='{{.State.Health.Status}}' "$c" 2>/dev/null | grep -q healthy; then break fi sleep 5 done done send_notification "Comserv Deploy SUCCESS on $HOSTNAME_VAL" "Both images deployed and healthy at $(date)."#!/bin/bash set -euo pipefail EMAIL="csc@computersystemconsulting.ca" COMPOSE_FILE="/opt/comserv/Comserv/docker-compose.server.yml" DEPLOY_LOG="/var/log/comserv-deploy.log" HOSTNAME_VAL=$(hostname) MAX_HEALTH_WAIT=120 IMAGES=("shantamcsbain/comserv-web-prod:latest" "shantamcsbain/comserv-api-prod:latest") CONTAINERS=("comserv2-web-prod" "comserv2-api-prod") exec > >(tee -a "$DEPLOY_LOG") 2>&1 send_notification() { local subject="$1" local body="$2" echo -e "Subject: $subject\n\n$body" | mail -s "$subject" "$EMAIL" || true } trap 'send_notification "Comserv Deploy FAILED on $HOSTNAME_VAL" "Deployment failed at $(date). Check $DEPLOY_LOG"; exit 1' ERR for i in "${!IMAGES[@]}"; do docker pull "${IMAGES[$i]}" done docker-compose -f "$COMPOSE_FILE" down docker-compose -f "$COMPOSE_FILE" up -d for c in "${CONTAINERS[@]}"; do for ((i=0; i<MAX_HEALTH_WAIT; i+=5)); do if docker inspect --format='